"""
Manages the overall state of the game, including the board, players, and current turn.
"""

class Game:
    def __init__(self):
        self.board = Board()
        self.player1 = Player('R')
        self.player2 = Player('B')
        self.current_player = self.player1

    def print_board(self):
        self.board.print_board()

    def switch_turn(self):
        if self.current_player == self.player1:
            self.current_player = self.player2
        else:
            self.current_player = self.player1

    def play(self):
        while True:
            self.print_board()
            move = input(f"{self.current_player.color}'s turn. Enter move (e.g., A1-A3): ")
            if move == 'quit':
                break
            from_pos, to_pos = move.split('-')
            if not self.board.is_valid_move(from_pos, to_pos):
                print("Invalid move. Try again.")
                continue
            self.board.make_move(from_pos, to_pos)
            self.switch_turn()

if __name__ == "__main__":
    game = Game()
    game.play()
